1338	///
1339	/// C: `static int str_gsub(lua_State *L)`
1340	pub fn str_gsub(state: &mut LuaState) -> Result<usize, LuaError> {
1341	    let src_bytes = state.check_arg_string(1)?;
1342	    let pat_bytes = state.check_arg_string(2)?;
1343	    let src_len = src_bytes.len();
1344	    let max_s = state.opt_arg_integer(4, (src_len + 1) as i64)?;
1345	    let tr = state.type_at(3);
1346	
1347	    // C: luaL_argexpected(..., tr == TNUMBER || tr == TSTRING || tr == TFUNCTION || tr == TTABLE, ...)
1348	    if !matches!(tr, LuaType::Number | LuaType::String | LuaType::Function | LuaType::Table) {
1349	        let v = state.arg(3);
1350	        return Err(LuaError::type_arg_error(3, "string/function/table", &v));
1351	    }
1352	
1353	    let src_owned = src_bytes.to_vec();
1354	    let pat_owned = pat_bytes.to_vec();
1355	
1356	    let anchor = pat_owned.first() == Some(&b'^');
1357	    let pat_slice = if anchor { &pat_owned[1..] } else { &pat_owned[..] };
1358	
1359	    let mut ms = MatchState::new(&src_owned, pat_slice);
1360	    let mut buf: Vec<u8> = Vec::new();
1361	    let mut src_pos = 0usize;
1362	    let mut last_match: Option<usize> = None;
1363	    let mut n: i64 = 0;
1364	    let mut changed = false;
1365	
1366	    while n < max_s {
1367	        ms.reset_level();
1368	        let maybe_e = match_pat(&mut ms, src_pos, 0)?;
1369	        if let Some(e) = maybe_e {
1370	            if last_match != Some(e) {
1371	                n += 1;
1372	                let delta = add_value(state, &ms, &mut buf, src_pos, e, tr)?;
1373	                changed |= delta;
1374	                src_pos = e;
1375	                last_match = Some(e);
1376	            } else if src_pos < ms.src.len() {
1377	                buf.push(ms.src[src_pos]);
1378	                src_pos += 1;
1379	            } else {
1380	                break;
1381	            }
1382	        } else if src_pos < ms.src.len() {
1383	            buf.push(ms.src[src_pos]);
1384	            src_pos += 1;
1385	        } else {
1386	            break;
1387	        }
1388	        if anchor {
1389	            break;
1390	        }
1391	    }
1392	
1393	    if !changed {
1394	        // C: lua_pushvalue(L, 1); /* return original string */
1395	        state.push_value_at(1)?;
1396	    } else {
1397	        buf.extend_from_slice(&ms.src[src_pos..]);
1398	        state.push_bytes(&buf)?;
