1408	/// Add a hex-float digit to buffer and return the fractional remainder.
1409	///
1410	/// C: `static lua_Number adddigit(char *buff, int n, lua_Number x)`
1411	fn adddigit(buf: &mut Vec<u8>, x: f64) -> f64 {
1412	    let dd = x.floor();
1413	    let d = dd as i32;
1414	    let c = if d < 10 { b'0' + d as u8 } else { b'a' + (d - 10) as u8 };
1415	    buf.push(c);
1416	    x - dd
1417	}
