1419	/// Convert a float to a hex-float string (like `%a`).
1420	///
1421	/// C: `static int num2straux(char *buff, int sz, lua_Number x)`
1422	fn num2straux(x: f64) -> Vec<u8> {
1423	    if x.is_nan() || x.is_infinite() {
1424	        // C: return l_sprintf(buff, sz, LUA_NUMBER_FMT, x);
1425	        // Use %g-like representation
1426	        return format!("{}", x).into_bytes();
1427	    }
1428	    if x == 0.0 {
1429	        // C: return l_sprintf(buff, sz, LUA_NUMBER_FMT "x0p+0", x);
1430	        if x.is_sign_negative() {
1431	            return b"-0x0p+0".to_vec();
1432	        }
1433	        return b"0x0p+0".to_vec();
1434	    }
1435	
1436	    let (m_raw, exp) = frexp(x);
1437	    let mut buf: Vec<u8> = Vec::new();
1438	    let mut m = m_raw;
1439	    if m < 0.0 {
1440	        buf.push(b'-');
1441	        m = -m;
1442	    }
1443	    buf.extend_from_slice(b"0x");
1444	
1445	    // C: L_NBFD = (MANT_DIG - 1) % 4 + 1  where MANT_DIG=53 → (52%4)+1 = 1
1446	    let nbfd = 1;
1447	    m = adddigit(&mut buf, m * (1 << nbfd) as f64);
1448	    let e = exp - nbfd;
1449	
1450	    if m > 0.0 {
1451	        buf.push(b'.');
1452	        while m > 0.0 {
1453	            m = adddigit(&mut buf, m * 16.0);
1454	        }
1455	    }
1456	
1457	    let exp_str = format!("p{:+}", e);
1458	    buf.extend_from_slice(exp_str.as_bytes());
1459	    buf
1460	}
