1462	/// Decompose `x` into mantissa in `[0.5, 1.0)` and exponent.
1463	/// Equivalent to C's `frexp`.
1464	fn frexp(x: f64) -> (f64, i32) {
1465	    if x == 0.0 || x.is_nan() || x.is_infinite() {
1466	        return (x, 0);
1467	    }
1468	    let bits = x.to_bits();
1469	    let exp_bits = ((bits >> 52) & 0x7FF) as i32;
1470	    if exp_bits == 0 {
1471	        // subnormal
1472	        let (m, e) = frexp(x * (1u64 << 52) as f64);
1473	        return (m, e - 52);
1474	    }
1475	    let exp = exp_bits - 1022;
1476	    let mantissa_bits = (bits & 0x000F_FFFF_FFFF_FFFF) | 0x3FE0_0000_0000_0000;
1477	    (f64::from_bits(mantissa_bits), exp)
1478	}
