    let end = state.top_idx().0.min(func_idx.0 + 4);
    for i in start..end {
        let v = state.get_at(StackIdx(i));
        let summary = match v {
            LuaValue::Nil => "Nil".to_string(),
            LuaValue::Bool(b) => format!("Bool({})", b),
            LuaValue::Int(n) => format!("Int({})", n),
            LuaValue::Float(f) => format!("Float({})", f),
            LuaValue::Str(s) => format!("Str(\"{}\")", String::from_utf8_lossy(s.as_bytes())),
            LuaValue::Table(_) => "Table".to_string(),
            LuaValue::Function(lua_types::closure::LuaClosure::Lua(cl)) => {
                format!("LuaFn(line{}..{})", cl.proto.linedefined, cl.proto.lastlinedefined)
            }
            LuaValue::Function(_) => "CFn".to_string(),
            _ => format!("{:?}", v.type_name()),
        };
        eprintln!("  [{}]: {}", i, summary);
    }
    return Err(LuaError::call_error(&offender));
}

